const HOP_SIZE: usize = 160; // 10ms at 16kHz
const PRE_EMPHASIS: f32 = 0.97; // initial high-pass
const LOG_ZERO_GUARD: f32 = 5.960_464_5e-08;

pub struct FeatureExtractor {
    buffer: Vec<i16>,
    prev: i16,
}

impl FeatureExtractor {
    pub fn new() -> Self {
        FeatureExtractor {
            buffer: Vec::new(),
            prev: 0,
        }
    }

    pub fn extract_features(&mut self,input: &[i16]) -> Vec<f32> {
        // splice tail with new audio
        let combined_len = self.buffer.len() + input.len();
        if combined_len < HANN_WINDOW_SIZE {
            self.buffer.extend_from_slice(input);
            if input.len() != 0 {
                self.prev = input[input.len() - 1];
            }
            return Vec::new();
        }

        // pre-emphasize
        let mut signal = Vec::with_capacity(combined_len);
        let mut prev = self.prev as f32 / 32768.0;
        for &s in self.buffer.iter().chain(input.iter()) {
            let cur = s as f32 / 32768.0;
            signal.push(cur - PRE_EMPHASIS * prev);
            prev = cur;
        }
        let num_frames = (signal.len() - HANN_WINDOW_SIZE) / HOP_SIZE + 1;
        if num_frames == 0 {
            self.buffer.extend_from_slice(input);
            if input.len() != 0 {
                self.prev = input[input.len() - 1];
            }
            return Vec::new();
        }

        // compute mel features
        let mut features = vec![0.0f32; num_frames * MEL_SIZE];
        for i in 0..num_frames {

            // create Hann windowed signal
            let start = i * HOP_SIZE;
            let mut windowed = vec![0.0f32; FFT_SIZE];
            for k in 0..HANN_WINDOW_SIZE {
                windowed[k] = signal[start + k] * HANN_WINDOW[k];
            }

            // compute DFT
            let mut spectrum = vec![0.0f32; SPECTRUM_SIZE];
            for k in 0..SPECTRUM_SIZE {
                let mut r = 0.0f32;
                let mut im = 0.0f32;
                for (t, &sample) in windowed.iter().enumerate() {
                    let angle = -2.0 * std::f32::consts::PI * k as f32 * t as f32 / FFT_SIZE as f32;
                    r += sample * angle.cos();
                    im += sample * angle.sin();
                }
                spectrum[k] = r * r + im * im;
            }

            // get mel features
            let frame_offset = i * MEL_SIZE;
            for k in 0..MEL_SIZE {
                let fb_offset = k * SPECTRUM_SIZE;
                let mut energy = 0.0f32;
                for l in 0..SPECTRUM_SIZE {
                    energy += MEL[fb_offset + l] * spectrum[l];
                }
                features[frame_offset + k] = (energy + LOG_ZERO_GUARD).ln();
            }
        }

        // save tail
        let consumed_samples = (num_frames - 1) * HOP_SIZE + HANN_WINDOW_SIZE;
        self.buffer.clear();
        let tail_start = consumed_samples;
        if tail_start < combined_len {
            let old_len = self.buffer.len();
            let _ = old_len;
            let audio_tail_start = input.len() as isize - (combined_len - tail_start) as isize;
            if audio_tail_start < 0 {

            }
            let remaining = combined_len - consumed_samples;
            if remaining <= input.len() {
                self.buffer.extend_from_slice(&input[input.len() - remaining..]);
            } else {
                self.buffer.extend_from_slice(input);
            }
        }

        if input.len() != 0 {
            self.prev = input[input.len() - 1];
        }

        features
    }

    pub fn reset(&mut self) {
        self.buffer.clear();
        self.prev = 0;
    }
}
